(function(){
  var v=document.getElementById('myVideo');
  if(!v) return 'NO_VIDEO';
  var tEl=document.getElementById('dyna_video_time');
  var target=tEl ? parseFloat(tEl.value) : NaN;
  var info=[
    'ct='+(v.currentTime||0),
    'paused='+(!!v.paused),
    'ended='+(!!v.ended),
    'readyState='+(v.readyState),
    'networkState='+(v.networkState),
    'dyna_video_time='+(isFinite(target)?target:'NaN')
  ].join(' | ');
  window.__uiv_ct1 = v.currentTime||0;
  return info;
})()

(function(){
  var v=document.getElementById('myVideo');
  if(!v) return 'NO_VIDEO';
  var ct2=v.currentTime||0;
  var ct1=(typeof window.__uiv_ct1==='number')?window.__uiv_ct1:NaN;
  var dt=(isFinite(ct1)&&isFinite(ct2))?(ct2-ct1):NaN;
  var tEl=document.getElementById('dyna_video_time');
  var target=tEl ? parseFloat(tEl.value) : NaN;
  var info=[
    'ct1='+(isFinite(ct1)?ct1:'NaN'),
    'ct2='+ct2,
    'dt='+(isFinite(dt)?dt:'NaN'),
    'paused='+(!!v.paused),
    'ended='+(!!v.ended),
    'readyState='+(v.readyState),
    'networkState='+(v.networkState),
    'dyna_video_time='+(isFinite(target)?target:'NaN')
  ].join(' | ');
  window.__uiv_dt = isFinite(dt)?dt:-999;
  return info;
})()

(function(){
  var cur=document.querySelector('tr.data.cur');
  if(!cur) return 'NO_CUR';
  var next=cur.nextElementSibling;
  while(next && !(next.matches && next.matches('tr.data'))) next=next.nextElementSibling;
  if(!next) return 'NO_NEXT';
  var title=(next.querySelector('p.title')||{}).textContent||'';
  return 'CLICK_NEXT title='+title.trim();
})()

(function(){
  var v=document.getElementById('myVideo');
  if(!v) return 'NO_VIDEO';
  var before=[v.paused,v.ended,v.currentTime,v.readyState,v.networkState].join(',');
  var r='';
  try{ v.muted=true; }catch(e){}
  try{ var p=v.play(); r=(p&&typeof p.then==='function')?'promise':'nopromise'; }catch(e){ r='PLAY_THROW:'+String(e); }
  var after=[v.paused,v.ended,v.currentTime,v.readyState,v.networkState].join(',');
  return 'play='+r+' | before='+before+' | after='+after;
})()
